import re
import argparse
from pathlib import Path
from abc import ABC, abstractmethod
from typing import List, Optional, Tuple

class FileProcessStrategy(ABC):
    """Abstract base class for file processing strategies."""

    @abstractmethod
    def process(self, file: Path, dry_run: bool = False) -> Tuple[Path, Path]:
        """Process a single file.

        Args:
            file: Path to the file to process
            dry_run: If True, only show what would be changed

        Returns:
            Tuple of (original_path, new_path)
        """
        pass

class RegexRenameStrategy(FileProcessStrategy):
    """Strategy for renaming files using regex patterns."""

    def __init__(self, pattern: str, replacement: str):
        """Initialize with regex pattern and replacement.

        Args:
            pattern: Regex pattern to match in filenames
            replacement: Replacement string (can use regex groups)
        """
        self.pattern = pattern
        self.replacement = replacement

    def process(self, file: Path, dry_run: bool = False) -> Tuple[Path, Path]:
        """Rename file using regex substitution."""
        new_name = re.sub(self.pattern, self.replacement, file.name)
        new_path = file.with_name(new_name)

        if not dry_run and new_path != file:
            file.rename(new_path)

        return (file, new_path)

class FileRenamer:
    """Main class for bulk file renaming."""

    def __init__(self, strategy: FileProcessStrategy):
        """Initialize with processing strategy."""
        self.strategy = strategy

    def process_files(self, files: List[Path], dry_run: bool = False) -> List[Tuple[Path, Path]]:
        """Process multiple files.

        Args:
            files: List of file paths to process
            dry_run: If True, only show what would be changed

        Returns:
            List of tuples (original_path, new_path)
        """
        results = []
        for file in files:
            if file.is_file():
                results.append(self.strategy.process(file, dry_run))
        return results

def get_files(directory: Path, recursive: bool = False) -> List[Path]:
    """Get files from directory, optionally recursively."""
    if recursive:
        return list(directory.rglob('*'))
    return list(directory.glob('*'))

def parse_args() -> argparse.Namespace:
    """Parse command line arguments."""
    parser = argparse.ArgumentParser(
        description="Bulk file renamer using regex patterns"
    )
    parser.add_argument(
        "pattern",
        help="Regex pattern to match in filenames"
    )
    parser.add_argument(
        "replacement",
        help="Replacement string (can use regex groups)"
    )
    parser.add_argument(
        "-d", "--directory",
        default=".",
        help="Directory containing files to rename (default: current directory)"
    )
    parser.add_argument(
        "-r", "--recursive",
        action="store_true",
        help="Process files recursively"
    )
    parser.add_argument(
        "-n", "--dry-run",
        action="store_true",
        help="Show what would be changed without actually renaming"
    )
    return parser.parse_args()

def main():
    args = parse_args()

    try:
        directory = Path(args.directory).resolve()
        if not directory.is_dir():
            raise ValueError(f"Directory not found: {directory}")

        files = get_files(directory, args.recursive)
        if not files:
            print("No files found to process")
            return

        strategy = RegexRenameStrategy(args.pattern, args.replacement)
        renamer = FileRenamer(strategy)

        results = renamer.process_files(files, args.dry_run)

        print(f"\n{'Dry run - ' if args.dry_run else ''}Processing results:")
        for original, new in results:
            if original != new:
                print(f"  {original.name} -> {new.name}")
            else:
                print(f"  {original.name} (no change)")

        changed = sum(1 for orig, new in results if orig != new)
        print(f"\nTotal files: {len(results)}, Changed: {changed}")

    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()

from functools import wraps
from typing import Callable, Dict


class CacheStrategy:
    """Base class for cache strategies"""
    def get(self, key: int) -> int:
        raise NotImplementedError

    def set(self, key: int, value: int) -> None:
        raise NotImplementedError


class DictCacheStrategy(CacheStrategy):
    """Concrete cache strategy using a dictionary"""
    def __init__(self):
        self._cache: Dict[int, int] = {}

    def get(self, key: int) -> int:
        return self._cache.get(key)

    def set(self, key: int, value: int) -> None:
        self._cache[key] = value


def memoize(cache_strategy: CacheStrategy) -> Callable:
    """Decorator factory that applies memoization with the given strategy"""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(n: int) -> int:
            cached = cache_strategy.get(n)
            if cached is not None:
                return cached
            result = func(n)
            cache_strategy.set(n, result)
            return result
        return wrapper
    return decorator


class FibonacciCalculator:
    def __init__(self, cache_strategy: CacheStrategy = DictCacheStrategy()):
        self.cache_strategy = cache_strategy
        # Apply memoization with the chosen strategy
        self.calculate = memoize(self.cache_strategy)(self._calculate)

    def _calculate(self, n: int) -> int:
        """Core recursive Fibonacci calculation"""
        if n < 0:
            raise ValueError("Fibonacci sequence is not defined for negative numbers")
        if n <= 1:
            return n
        return self.calculate(n - 1) + self.calculate(n - 2)


# Example usage
if __name__ == "__main__":
    # Create calculator with default dictionary cache
    fib_calc = FibonacciCalculator()

    # Calculate some Fibonacci numbers
    print(fib_calc.calculate(10))  # 55
    print(fib_calc.calculate(20))  # 6765

    # You could easily swap in a different cache strategy:
    # class RedisCacheStrategy(CacheStrategy): ...
    # fib_calc = FibonacciCalculator(RedisCacheStrategy())

from enum import Enum, auto
from typing import Callable, Optional


class TcpState(Enum):
    """TCP connection states as defined in RFC 793."""
    CLOSED = auto()
    LISTEN = auto()
    SYN_SENT = auto()
    SYN_RECEIVED = auto()
    ESTABLISHED = auto()
    FIN_WAIT_1 = auto()
    FIN_WAIT_2 = auto()
    CLOSE_WAIT = auto()
    CLOSING = auto()
    LAST_ACK = auto()
    TIME_WAIT = auto()


class TcpConnection:
    """State machine for TCP connection handling."""

    def __init__(self):
        self.state = TcpState.CLOSED
        self.transitions = {
            TcpState.CLOSED: self._handle_closed,
            TcpState.LISTEN: self._handle_listen,
            TcpState.SYN_SENT: self._handle_syn_sent,
            TcpState.SYN_RECEIVED: self._handle_syn_received,
            TcpState.ESTABLISHED: self._handle_established,
            TcpState.FIN_WAIT_1: self._handle_fin_wait_1,
            TcpState.FIN_WAIT_2: self._handle_fin_wait_2,
            TcpState.CLOSE_WAIT: self._handle_close_wait,
            TcpState.CLOSING: self._handle_closing,
            TcpState.LAST_ACK: self._handle_last_ack,
            TcpState.TIME_WAIT: self._handle_time_wait,
        }

    def process_event(self, event: str) -> Optional[str]:
        """Process an event and transition to next state."""
        handler = self.transitions.get(self.state)
        if not handler:
            return f"No handler for state {self.state}"

        return handler(event)

    def _handle_closed(self, event: str) -> str:
        if event == "passive_open":
            self.state = TcpState.LISTEN
            return "Transitioned to LISTEN"
        if event == "active_open":
            self.state = TcpState.SYN_SENT
            return "Transitioned to SYN_SENT"
        return f"Invalid event {event} for CLOSED state"

    def _handle_listen(self, event: str) -> str:
        if event == "rcv_syn":
            self.state = TcpState.SYN_RECEIVED
            return "Transitioned to SYN_RECEIVED"
        if event == "send_syn":
            self.state = TcpState.SYN_SENT
            return "Transitioned to SYN_SENT"
        if event == "close":
            self.state = TcpState.CLOSED
            return "Transitioned to CLOSED"
        return f"Invalid event {event} for LISTEN state"

    def _handle_syn_sent(self, event: str) -> str:
        if event == "rcv_syn_ack":
            self.state = TcpState.ESTABLISHED
            return "Transitioned to ESTABLISHED"
        if event == "rcv_syn":
            self.state = TcpState.SYN_RECEIVED
            return "Transitioned to SYN_RECEIVED"
        if event == "close":
            self.state = TcpState.CLOSED
            return "Transitioned to CLOSED"
        return f"Invalid event {event} for SYN_SENT state"

    def _handle_syn_received(self, event: str) -> str:
        if event == "rcv_ack":
            self.state = TcpState.ESTABLISHED
            return "Transitioned to ESTABLISHED"
        if event == "close":
            self.state = TcpState.FIN_WAIT_1
            return "Transitioned to FIN_WAIT_1"
        return f"Invalid event {event} for SYN_RECEIVED state"

    def _handle_established(self, event: str) -> str:
        if event == "close":
            self.state = TcpState.FIN_WAIT_1
            return "Transitioned to FIN_WAIT_1"
        if event == "rcv_fin":
            self.state = TcpState.CLOSE_WAIT
            return "Transitioned to CLOSE_WAIT"
        return f"Invalid event {event} for ESTABLISHED state"

    def _handle_fin_wait_1(self, event: str) -> str:
        if event == "rcv_fin":
            self.state = TcpState.CLOSING
            return "Transitioned to CLOSING"
        if event == "rcv_fin_ack":
            self.state = TcpState.TIME_WAIT
            return "Transitioned to TIME_WAIT"
        if event == "rcv_ack":
            self.state = TcpState.FIN_WAIT_2
            return "Transitioned to FIN_WAIT_2"
        return f"Invalid event {event} for FIN_WAIT_1 state"

    def _handle_fin_wait_2(self, event: str) -> str:
        if event == "rcv_fin":
            self.state = TcpState.TIME_WAIT
            return "Transitioned to TIME_WAIT"
        return f"Invalid event {event} for FIN_WAIT_2 state"

    def _handle_close_wait(self, event: str) -> str:
        if event == "close":
            self.state = TcpState.LAST_ACK
            return "Transitioned to LAST_ACK"
        return f"Invalid event {event} for CLOSE_WAIT state"

    def _handle_closing(self, event: str) -> str:
        if event == "rcv_ack":
            self.state = TcpState.TIME_WAIT
            return "Transitioned to TIME_WAIT"
        return f"Invalid event {event} for CLOSING state"

    def _handle_last_ack(self, event: str) -> str:
        if event == "rcv_ack":
            self.state = TcpState.CLOSED
            return "Transitioned to CLOSED"
        return f"Invalid event {event} for LAST_ACK state"

    def _handle_time_wait(self, event: str) -> str:
        if event == "timeout":
            self.state = TcpState.CLOSED
            return "Transitioned to CLOSED"
        return f"Invalid event {event} for TIME_WAIT state"


# Example usage
if __name__ == "__main__":
    conn = TcpConnection()
    print(f"Initial state: {conn.state}")

    print(conn.process_event("active_open"))
    print(f"Current state: {conn.state}")

    print(conn.process_event("rcv_syn_ack"))
    print(f"Current state: {conn.state}")

    print(conn.process_event("close"))
    print(f"Current state: {conn.state}")

import sqlite3
from abc import ABC, abstractmethod
from typing import List, Dict
import random
import time
import threading

# Observer interface
class StockObserver(ABC):
    @abstractmethod
    def update(self, stock_symbol: str, price: float):
        pass

# Subject (Publisher) class
class StockPublisher:
    def __init__(self):
        self._observers: List[StockObserver] = []
        self._stocks: Dict[str, float] = {}
        self._db_conn = sqlite3.connect(':memory:')
        self._setup_database()

    def _setup_database(self):
        cursor = self._db_conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS stock_history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                symbol TEXT NOT NULL,
                price REAL NOT NULL,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        """)
        self._db_conn.commit()

    def add_observer(self, observer: StockObserver):
        if observer not in self._observers:
            self._observers.append(observer)

    def remove_observer(self, observer: StockObserver):
        self._observers.remove(observer)

    def notify_observers(self, stock_symbol: str):
        price = self._stocks[stock_symbol]
        for observer in self._observers:
            observer.update(stock_symbol, price)

    def update_stock_price(self, stock_symbol: str, price: float):
        self._stocks[stock_symbol] = price

        # Safe SQL parameterization
        cursor = self._db_conn.cursor()
        cursor.execute(
            "INSERT INTO stock_history (symbol, price) VALUES (?, ?)",
            (stock_symbol, price)
        )
        self._db_conn.commit()

        self.notify_observers(stock_symbol)

    def get_price_history(self, stock_symbol: str) -> List[Dict]:
        cursor = self._db_conn.cursor()
        cursor.execute(
            "SELECT symbol, price, timestamp FROM stock_history WHERE symbol = ? ORDER BY timestamp DESC",
            (stock_symbol,)
        )
        return [
            {"symbol": row[0], "price": row[1], "timestamp": row[2]}
            for row in cursor.fetchall()
        ]

    def start_price_simulation(self):
        def simulate():
            while True:
                for symbol in self._stocks.keys():
                    new_price = round(random.uniform(100, 200), 2)
                    self.update_stock_price(symbol, new_price)
                time.sleep(2)

        thread = threading.Thread(target=simulate, daemon=True)
        thread.start()

# Concrete Observer
class StockDisplay(StockObserver):
    def update(self, stock_symbol: str, price: float):
        print(f"[DISPLAY] {stock_symbol}: ${price:.2f}")

# Another Concrete Observer
class StockAlert(StockObserver):
    def __init__(self, threshold: float):
        self.threshold = threshold

    def update(self, stock_symbol: str, price: float):
        if price > self.threshold:
            print(f"[ALERT] {stock_symbol} is above threshold! Price: ${price:.2f}")

# Usage example
if __name__ == "__main__":
    publisher = StockPublisher()

    # Initialize some stocks
    publisher.update_stock_price("AAPL", 150.00)
    publisher.update_stock_price("GOOGL", 180.50)
    publisher.update_stock_price("MSFT", 120.75)

    # Create observers
    display = StockDisplay()
    alert = StockAlert(170.00)

    # Register observers
    publisher.add_observer(display)
    publisher.add_observer(alert)

    # Start price simulation
    publisher.start_price_simulation()

    # Keep the program running to see updates
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("\nStopping stock updates...")

