# Filename: plugin_manager.py
from typing import Type, Dict

class PluginManager:
    def __init__(self):
        self.transformers = {}
        self.formatters = {}

    def add_transformer(self, name: str, transformer_class: Type['MarkdownTransformer']):
        self.transformers[name] = transformer_class()

    def add_formatter(self, name: str, formatter_class: Type['OutputFormatter']):
        self.formatters[name] = formatter_class()

    def get_transformer(self, name: str):
        return self.transformers.get(name)

    def get_formatter(self, name: str):
        return self.formatters.get(name)

# Filename: markdown_transformer.py
class MarkdownTransformer:
    def transform(self, markdown_text: str) -> str:
        raise NotImplementedError

# Filename: output_formatter.py
class OutputFormatter:
    def format(self, text: str) -> str:
        raise NotImplementedError

# Developer implements these in separate files or plugins
# Filename: html_output.py
class HTMLOutputFormatter(OutputFormatter):
    def format(self, text: str) -> str:
        return f"<html><body>{text}</body></html>"

# Filename: pdf_output.py
class PDFOutputFormatter(OutputFormatter):
    def format(self, text: str) -> str:
        # Implementation would be using PDF library
        return f"PDF Converted: {text}"

# Filename: simple_markdown_transformer.py
class SimpleMarkdownTransformer(MarkdownTransformer):
    def transform(self, markdown_text: str) -> str:
        return markdown_text.replace('#', 'H1: ').replace('*', 'Bold: ')

# Filename: main.py
def main():
    plugin_manager = PluginManager()

    # Registering plugins
    plugin_manager.add_formatter('html', HTMLOutputFormatter)
    plugin_manager.add_formatter('pdf', PDFOutputFormatter)
    plugin_manager.add_transformer('simple', SimpleMarkdownTransformer)

    # Example usage
    transformer = plugin_manager.get_transformer('simple')
    formatter = plugin_manager.get_formatter('html')

    markdown_text = "# Hello *World*"
    transformed_text = transformer.transform(markdown_text)
    formatted_output = formatter.format(transformed_text)

    print(formatted_output)

if __name__ == "__main__":
    main()

