package main

import (
	"log"
	"net/http"
	"encoding/json"
	"github.com/sirupsen/logrus"
	"time"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

type ApiResponse struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

func main() {
	logger := logrus.New()
	logger.Formatter = &logrus.JSONFormatter{}
	logger.Level = logrus.InfoLevel

	r := chi.NewRouter()
	r.Use(middleware.RequestID)
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(middleware.Timeout(60 * time.Second))

	r.Get("/", func(w http.ResponseWriter, r *http.Request) {
		response := ApiResponse{"ok", "Service is up and running"}
		respondWithJSON(w, http.StatusOK, response)
	})

	r.Post("/data", func(w http.ResponseWriter, r *http.Request) {
		var data map[string]interface{}
		err := json.NewDecoder(r.Body).Decode(&data)
		if err != nil {
			logger.WithFields(logrus.Fields{
				"error": err,
			}).Error("Failed to decode input data")
			respondWithError(w, http.StatusBadRequest, "Invalid request payload")
			return
		}

		if ok := externalAPIProcess(data); !ok {
			logger.Error("External API failure")
			respondWithError(w, http.StatusServiceUnavailable, "Failed to process data due to external API failure")
			return
		}

		response := ApiResponse{"success", "Data processed successfully"}
		respondWithJSON(w, http.StatusOK, response)
	})

	http.ListenAndServe(":8080", r)
}

func externalAPIProcess(data map[string]interface{}) bool {
	// Simulating external API processing and their associated failures
	if _, ok := data["corrupt"]; ok {
		return false
	}
	return true
}

func respondWithJSON(w http.ResponseWriter, statusCode int, payload interface{}) {
	response, _ := json.Marshal(payload)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	w.Write(response)
}

func respondWithError(w http.ResponseWriter, statusCode int, message string) {
	respondWithJSON(w, statusCode, map[string]string{"error": message})
}
