import datetime
from typing import List, Dict, Optional

class TransactionRecord:
    def __init__(self, user_id: str, timestamp: datetime.datetime, action: str, details: str):
        self.user_id = user_id
        self.timestamp = timestamp
        self.action = action
        self.details = details

    def __repr__(self):
        return f"{self.timestamp} - {self.user_id} - {self.action}: {self.details}"

class ImmutableLedger:
    def __init__(self):
        self.records: List[TransactionRecord] = []

    def add_record(self, user_id: str, action: str, details: str):
        timestamp = datetime.datetime.now()
        record = TransactionRecord(user_id, timestamp, action, details)
        self.records.append(record)

    def get_records(self, user_id: Optional[str]=None) -> List[TransactionRecord]:
        if user_id:
            return [record for record in self.records if record.user_id == user_id]
        return self.records.copy()

    def __repr__(self):
        return "\n".join(repr(record) for record in self.records)

if __name__ == "__main__":
    ledger = ImmutableLedger()
    ledger.add_record(user_id="User123", action="Deposit", details="Deposited $500")
    ledger.add_record(user_id="User456", action="Withdrawal", details="Withdrew $100")
    ledger.add_record(user_id="User123", action="Transfer", details="Transferred $300 to User456")

    print(ledger)
    print("\nFiltered by User123:")
    print(ledger.get_records("User123"))
