package main

import (
	"fmt"
	"log"
	"sync"
	"time"

	"github.com/golang/glog"
	"github.com/juju/ratelimit"
	"github.com/streadway/amqp"
)

type Consumer struct {
	conn       *amqp.Connection
	queue      string
	workers    int
	bucket     *ratelimit.Bucket
	wg         sync.WaitGroup
	stopChan   chan bool
}

func NewConsumer(amqpURL, queueName string, workers int, rateLimit float64) (*Consumer, error) {
	conn, err := amqp.Dial(amqpURL)
	if err != nil {
		return nil, fmt.Errorf("dial: %s", err)
	}

	bucket := ratelimit.NewBucketWithRate(rateLimit, int64(rateLimit))

	consumer := &Consumer{
		conn:       conn,
		queue:      queueName,
		workers:    workers,
		bucket:     bucket,
		stopChan:   make(chan bool),
	}
	return consumer, nil
}

func (c *Consumer) processMessage(msg []byte) {
	fmt.Printf("Processing message: %s\n", msg)
	// Simulate work
	time.Sleep(1 * time.Second)
}

func (c *Consumer) handleDelivery(deliveries <-chan amqp.Delivery, id int) {
	defer c.wg.Done()
	for d := range deliveries {
		c.bucket.Wait(1) // Rate limit the consumer
		glog.Infof("worker %d received message: %s\n", id, d.Body)
		c.processMessage(d.Body)
		err := d.Ack(false)
		if err != nil {
			glog.Errorf("worker %d error acknowledging message: %s, error: %v", id, d.Body, err)
		}
	}
}

func (c *Consumer) Consume() {
	ch, err := c.conn.Channel()
	if err != nil {
		log.Fatalf("channel: %s", err)
	}

	deliveries, err := ch.Consume(
		c.queue, // queue
		"",      // consumer
		false,   // auto-ack
		false,   // exclusive
		false,   // no-local
		false,   // no-wait
		nil,     // args
	)
	if err != nil {
		log.Fatalf("queue consume: %s", err)
	}

	for i := 0; i < c.workers; i++ {
		c.wg.Add(1)
		go c.handleDelivery(deliveries, i)
	}

	<-c.stopChan
	ch.Close()
}

func (c *Consumer) Stop() {
	close(c.stopChan)
	c.wg.Wait()
	c.conn.Close()
}

func main() {
	// Set these values based on your AMQP server setup
	amqpURL := "amqp://guest:guest@localhost:5672/"
	queueName := "user_signups"
	workers := 5
	rateLimit := 10.0 // messages per second

	consumer, err := NewConsumer(amqpURL, queueName, workers, rateLimit)
	if err != nil {
		log.Fatalf("Failed to create consumer: %s", err)
	}

	go consumer.Consume()

	// Run the consumer indefinitely
	forever := make(chan bool)
	<-forever
}
