import time
from requests import get
from requests.exceptions import RequestException

class CircuitBreaker:
    def __init__(self):
        self.state = 'CLOSED'
        self.failure_count = 0
        self.success_count = 0
        self.next_allowed_time = 0

    def call(self, url):
        if self.state == 'OPEN':
            if time.time() < self.next_allowed_time:
                raise Exception('Circuit is open; requests are not allowed')
            else:
                self.state = 'HALF_OPEN'
                print(f"Transitioned to HALF_OPEN state. Testing with a request to {url}")

        try:
            response = get(url)
            self._on_success()
            return response
        except RequestException:
            self._on_failure()
            raise

    def _on_success(self):
        if self.state == 'HALF_OPEN':
            self.success_count += 1
            if self.success_count >= 5:
                self._reset()
                print('Transitioned to CLOSED state after consecutive successful attempts')
        else:
            self.success_count = 0

    def _on_failure(self):
        self.failure_count += 1
        if self.state == 'HALF_OPEN':
            self._enter_open_state()
        else:
            if self.failure_count >= 3:
                self._enter_open_state()

    def _enter_open_state(self):
        self.state = 'OPEN'
        self.next_allowed_time = time.time() + self._calculate_backoff()
        self.failure_count = 0
        self.success_count = 0
        print(f"Transitioned to OPEN state. Next allowed time: {self.next_allowed_time}")

    def _calculate_backoff(self):
        return min(60, 2 ** self.failure_count - 1)

    def _reset(self):
        self.state = 'CLOSED'
        self.failure_count = 0
        self.success_count = 0

# Usage
circuit_breaker = CircuitBreaker()
for _ in range(10):
    try:
        print(circuit_breaker.call('https://api.example.com'))
    except Exception as e:
        print(e)
    time.sleep(1)
```
This Python code implements a circuit breaker pattern with exponential backoff for HTTP requests, tracks the failure rates, manages half-open state testing, and integrates automatic recovery after 5 consecutive successful requests.

