import hashlib
import bisect
import json
import socket
import threading
import time
import random
from collections import defaultdict

class ConsistentHashing:
    def __init__(self, num_vnodes=100):
        self.num_vnodes = num_vnodes
        self.ring = []
        self.vnode_to_node = {}

    def _hash(self, key):
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def add_node(self, node_id):
        for i in range(self.num_vnodes):
            hsh = self._hash(f"{node_id}_vnode_{i}")
            bisect.insort(self.ring, hsh)
            self.vnode_to_node[hsh] = node_id

    def remove_node(self, node_id):
        to_remove = [self._hash(f"{node_id}_vnode_{i}") for i in range(self.num_vnodes)]
        self.ring = [h for h in self.ring if h not in to_remove]
        for hsh in to_remove:
            del self.vnode_to_node[hsh]

    def get_node(self, key):
        hsh = self._hash(key)
        pos = bisect.bisect(self.ring, hsh) % len(self.ring)
        return self.vnode_to_node[self.ring[pos]]

class GossipProtocol:
    def __init__(self, nodes, local_node):
        self.nodes = nodes
        self.local_node = local_node
        self.membership_list = {node: {'last_seen': time.time()} for node in nodes}
        self.lock = threading.Lock()

    def gossip(self):
        while True:
            with self.lock:
                other_node = random.choice([node for node in self.nodes if node != self.local_node])
            self.send_membership_table(other_node)
            time.sleep(1)

    def send_membership_table(self, node):
        data = json.dumps(self.membership_list).encode('utf-8')
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.sendto(data, (node, 50000))

    def receive_membership_table(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.bind((self.local_node, 50000))
        while True:
            data, _ = sock.recvfrom(4096)
            with self.lock:
                other_membership = json.loads(data.decode('utf-8'))
                for node, info in other_membership.items():
                    if node not in self.membership_list or info['last_seen'] > self.membership_list[node]['last_seen']:
                        self.membership_list[node] = info

    def remove_failed_nodes(self):
        while True:
            with self.lock:
                current_time = time.time()
                failed_nodes = [node for node, info in self.membership_list.items() if current_time - info['last_seen'] > 5]
                for node in failed_nodes:
                    del self.membership_list[node]
            time.sleep(1)

    def update_last_seen(self, node, timestamp):
        with self.lock:
            if node in self.membership_list:
                self.membership_list[node]['last_seen'] = timestamp

class KeyValueStore:
    def __init__(self, node_id, nodes):
        self.node_id = node_id
        self.data = {}
        self.consistent_hash = ConsistentHashing()
        for node in nodes:
            self.consistent_hash.add_node(node)

        self.gossip = GossipProtocol(nodes, self.node_id)
        threading.Thread(target=self.gossip.gossip).start()
        threading.Thread(target=self.gossip.receive_membership_table).start()
        threading.Thread(target=self.gossip.remove_failed_nodes).start()

    def add(self, key, value):
        node = self.consistent_hash.get_node(key)
        if node == self.node_id:
            self.data[key] = value
        else:
            forward_data(key, value, node)

    def get(self, key):
        node = self.consistent_hash.get_node(key)
        if node == self.node_id:
            return self.data.get(key, None)
        else:
            return forward_request(key, node)

def forward_data(key, value, node):
    # Implement networking logic to forward data to the correct node
    pass

def forward_request(key, node):
    # Implement networking logic to request data from the correct node
    pass

# Usage example:
