import os
import boto3
import google.cloud.storage as gcs
from typing import Union
from unittest.mock import Mock
from abc import ABC, abstractmethod

class StorageAdapter(ABC):
    @abstractmethod
    def upload(self, file_path: str, bucket: str, object_name: str) -> None:
        pass

    @abstractmethod
    def download(self, bucket: str, object_name: str, dest_path: str) -> None:
        pass

class S3StorageAdapter(StorageAdapter):
    def __init__(self, client: boto3.client):
        self.client = client

    def upload(self, file_path: str, bucket: str, object_name: str) -> None:
        self.client.upload_file(file_path, bucket, object_name)

    def download(self, bucket: str, object_name: str, dest_path: str) -> None:
        self.client.download_file(bucket, object_name, dest_path)

class GCSStorageAdapter(StorageAdapter):
    def __init__(self, client: gcs.Client):
        self.client = client

    def upload(self, file_path: str, bucket: str, object_name: str) -> None:
        bucket = self.client.bucket(bucket)
        blob = bucket.blob(object_name)
        blob.upload_from_filename(file_path)

    def download(self, bucket: str, object_name: str, dest_path: str) -> None:
        bucket = self.client.bucket(bucket)
        blob = bucket.blob(object_name)
        blob.download_to_filename(dest_path)

class LocalStorageAdapter(StorageAdapter):
    def upload(self, file_path: str, bucket: str, object_name: str) -> None:
        os.makedirs(os.path.join(bucket, os.path.dirname(object_name)), exist_ok=True)
        os.rename(file_path, os.path.join(bucket, object_name))

    def download(self, bucket: str, object_name: str, dest_path: str) -> None:
        os.makedirs(os.path.dirname(dest_path), exist_ok=True)
        os.rename(os.path.join(bucket, object_name), dest_path)

class StorageService:
    def __init__(self, storage_adapter: StorageAdapter):
        self.adapter = storage_adapter

    def upload(self, file_path: str, bucket: str, object_name: str) -> None:
        self.adapter.upload(file_path, bucket, object_name)

    def download(self, bucket: str, object_name: str, dest_path: str) -> None:
        self.adapter.download(bucket, object_name, dest_path)

# Dependency injection
def get_storage_adapter(provider: Union[S3StorageAdapter, GCSStorageAdapter, LocalStorageAdapter], client=None) -> StorageAdapter:
    if provider == 's3':
        s3_client = client if client else boto3.client('s3')
        return S3StorageAdapter(s3_client)
    elif provider == 'gcs':
        gcs_client = client if client else gcs.Client()
        return GCSStorageAdapter(gcs_client)
    elif provider == 'local':
        return LocalStorageAdapter()
    else:
        raise ValueError("Unsupported storage provider")

