from pygments.formatters import TerminalFormatter

class ServerConfigWizard:
    def __init__(self):
        self.history = []
        self.history_index = -1
        self.config = {}

    def load_config_schema(self):
        self.schema = {
            "server_name": {
                "type": "string",
                "help": "Enter the server's name."
            },
            "port": {
                "type": "int",
                "help": "Enter the server's port number."
            },
            "use_ssl": {
                "type": "bool",
                "help": "Should the server use SSL (True/False)?"
            }
        }

    def render_config_preview(self):
        config_json = json.dumps(self.config, indent=4)
        print(highlight(config_json, JsonLexer(), TerminalFormatter()))

    def modify_config(self, key, value):
        if key in self.schema:
            try:
                if self.schema[key]['type'] == 'int':
                    value = int(value)
                elif self.schema[key]['type'] == 'bool':
                    value = value.lower() in ("true", "yes", "1")
                self.config[key] = value
                self.save_history()
            except ValueError:
                print(f"Error: {key} needs to be of type {self.schema[key]['type']}.")

    def undo(self):
        if self.history_index > 0:
            self.history_index -= 1
            self.config = self.history[self.history_index]

    def redo(self):
        if self.history_index < len(self.history) - 1:
            self.history_index += 1
            self.config = self.history[self.history_index]

    def save_history(self):
        self.history = self.history[:self.history_index + 1]
        self.history.append(self.config.copy())
        self.history_index += 1

    def input_with_help(self, key):
        user_input = input(f"Enter {key} (type 'help' for more info): ")
        if user_input.lower() == 'help':
            print(self.schema[key]['help'])
            return self.input_with_help(key)
        return user_input

    def configure(self):
        for key in self.schema:
            value = self.input_with_help(key)
            self.modify_config(key, value)
        self.render_config_preview()

def setup_autocomplete(schema):
    def completer(text, state):
        options = [i for i in schema.keys() if i.startswith(text)]
        if state < len(options):
            return options[state]
        return None

    readline.set_completer(completer)
    readline.parse_and_bind("tab: complete")

def main():
    wizard = ServerConfigWizard()
    wizard.load_config_schema()
    setup_autocomplete(wizard.schema)
    wizard.configure()

if __name__ == "__main__":
    main()
