import os
import boto3
from flask import Flask, request, jsonify
from hashlib import md5

app = Flask(__name__)
s3 = boto3.client('s3')
BUCKET_NAME = 'your-bucket-name'

class UploadManager:
    def __init__(self):
        self.active_uploads = {}

    def start_upload(self, file_id, file_size, chunk_size):
        if file_id in self.active_uploads:
            return False  # Upload is already in progress

        self.active_uploads[file_id] = {
            "size": file_size,
            "chunks": [None] * ((file_size + chunk_size - 1) // chunk_size),
            "check_md5": md5(),
            "upload_id": None  # S3 Multipart Upload ID
        }
        return True

    def upload_chunk(self, file_id, chunk_index, chunk_data):
        upload_info = self.active_uploads.get(file_id)
        if not upload_info:
            return False  # No such upload in progress

        if upload_info["chunks"][chunk_index] is None:  # Idempotency check
            upload_info["chunks"][chunk_index] = chunk_data
            upload_info["check_md5"].update(chunk_data)

            if upload_info["upload_id"] is None:  # Start S3 Multipart upload if necessary
                resp = s3.create_multipart_upload(Bucket=BUCKET_NAME, Key=file_id)
                upload_info["upload_id"] = resp['UploadId']

            part_number = chunk_index + 1
            resp = s3.upload_part(
                Bucket=BUCKET_NAME, Key=file_id, PartNumber=part_number,
                UploadId=upload_info["upload_id"], Body=chunk_data
            )
            return {"ETag": resp['ETag'], "PartNumber": part_number}
        return True

    def complete_upload(self, file_id, client_md5):
        upload_info = self.active_uploads.get(file_id)
        if not upload_info:
            return False  # No such upload

        s3_etags = [{"ETag": part["ETag"], "PartNumber": part["PartNumber"]} 
                    for part in upload_info["chunks"] if part is not None]

        # Complete multipart upload
        s3.complete_multipart_upload(
            Bucket=BUCKET_NAME, Key=file_id, UploadId=upload_info["upload_id"],
            MultipartUpload={"Parts": s3_etags}
        )

        # Verify checksum
        server_md5 = upload_info["check_md5"].hexdigest()
        if server_md5 != client_md5:
            s3.delete_object(Bucket=BUCKET_NAME, Key=file_id)
            return {"error": "MD5 checksum verification failed"}

        del self.active_uploads[file_id]  # Cleanup upload session data
        return {"message": "Upload successful", "checksum": server_md5}

upload_manager = UploadManager()

@app.route('/upload/start', methods=['POST'])
def start_upload():
    file_info = request.json
    file_id = file_info['file_id']
    file_size = int(file_info['file_size'])
    chunk_size = int(file_info['chunk_size'])
    success = upload_manager.start_upload(file_id, file_size, chunk_size)
    if not success:
        return jsonify({"error": "Upload already in progress"}), 409
    return jsonify({"message": "Upload started"}), 201

@app.route('/upload/chunk', methods=['POST'])
def upload_chunk():
    file_id = request.args.get('file_id')
    chunk_index = int(request.args.get('chunk_index'))
    chunk_data = request.data  # Directly access the binary data from the request
    result = upload_manager.upload_chunk(file_id, chunk_index, chunk_data)
    if isinstance(result, dict):
        return jsonify(result), 200
    return jsonify({"error": "Failed to upload chunk"}), 500

@app.route('/upload/complete', methods=['POST'])
def complete_upload():
    file_info = request.json
    file_id = file_info['file_id']
    client_md5 = file_info['md5']
    result = upload_manager.complete_upload(file_id, client_md5)
    if "error" in result:
        return jsonify(result), 500
    return jsonify(result), 200

if __name__ == '__main__':
    app.run()
```
This Python Flask application configures a secure file upload service capable of handling chunked uploads with checksum verification, resumable transfers, atomic writes on completion, and uses S3 multipart upload fallback for integrating with AWS storage. It deals with network fluctuations using retries and manages idempotency through token checks.

