import pygments
from pygments.lexers import SqlLexer
from pygments.formatters import TerminalFormatter
from prompt_toolkit import PromptSession
from prompt_toolkit.completion import WordCompleter
from prompt_toolkit.shortcuts import confirm
from sqlalchemy import create_engine, text
from rich.table import Table
from rich.console import Console

# Define global variables for the undo stack and the database engine
undo_stack = []
engine = None

# SQL keywords for autocompletion
sql_completer = WordCompleter([
    'SELECT', 'FROM', 'WHERE', 'INSERT', 'INTO', 'VALUES', 'UPDATE', 'SET', 'DELETE',
    'CREATE', 'TABLE', 'DROP', 'ALTER', 'ADD', 'COLUMN', 'INDEX', 
    'UNION', 'ALL', 'LEFT', 'JOIN', 'ON', 'GROUP', 'BY', 'ORDER', 'LIMIT'
], ignore_case=True)

def setup_database_connection(database_url):
    global engine
    engine = create_engine(database_url)

def execute_query(query, is_dry_run=False):
    if is_dry_run:
        print("Dry run enabled. Query will not be executed:")
        print_query(query)
        return None

    with engine.connect() as connection:
        result = connection.execute(text(query))
        if result.returns_rows:
            return result.fetchall()
        undo_stack.append(query)

def print_query(query):
    highlighted_query = pygments.highlight(query, SqlLexer(), TerminalFormatter())
    print(highlighted_query)

def print_result(result):
    console = Console()
    table = Table(show_header=True)
    if result:
        headers = result[0].keys()
        for header in headers:
            table.add_column(header)
        for row in result:
            table.add_row(*[str(cell) for cell in row.values()])
        console.print(table)

def undo_last_query():
    if not undo_stack:
        print("Undo stack is empty.")
        return

    last_query = undo_stack.pop()
    print(f"Undoing last query: {last_query}")
    # Here should be the logic to inverse the last query, depending on the type of the last query
    # For simplicity, not implemented here

def main():
    session = PromptSession(completer=sql_completer)
    while True:
        try:
            query = session.prompt("SQL> ", lexer=SqlLexer())
            if query.lower().strip() == "exit":
                break
            if query.lower().strip() == "undo":
                undo_last_query()
                continue
            is_dry_run = confirm("Execute as dry-run?")
            results = execute_query(query, is_dry_run=is_dry_run)
            if results:
                print_result(results)
        except KeyboardInterrupt:
            continue
        except EOFError:
            break
        except Exception as e:
            print(f"Error: {str(e)}")

if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python migration_tool.py <database_url>")
    else:
        setup_database_connection(sys.argv[1])
        main()
