const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'https://yourapp.com/oauth/callback';
const authorizationEndpoint = 'https://provider.com/oauth/authorize';
const tokenEndpoint = 'https://provider.com/oauth/token';

// Create Express app
const app = express();

// Helmet for setting Content-Security-Policy
app.use(helmet.contentSecurityPolicy({
  directives: {
    defaultSrc: ["'self'"],
    scriptSrc: ["'self'"],
    objectSrc: ["'none'"],
    upgradeInsecureRequests: [],
  },
}));

// Parse cookies
app.use(cookieParser());

// CSRF protection
const csrfProtection = csrf({ cookie: true });
app.use(csrfProtection);

// Function to generate a secure random string for PKCE
const generateRandomString = () => {
  return require('crypto').randomBytes(32).toString('hex');
};

// Generate code verifier and code challenge
const generateCodeChallenge = (codeVerifier) => {
  return require('crypto')
    .createHash('sha256')
    .update(codeVerifier)
    .digest()
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

// Store generated states, code_verifier in a more secure storage
let states = {};
let codeVerifiers = {};

// Login route
app.get('/login', (req, res) => {
  const state = generateRandomString();
  const codeVerifier = generateRandomString();
  const codeChallenge = generateCodeChallenge(codeVerifier);

  states[state] = true;
  codeVerifiers[state] = codeVerifier;

  const queryParams = new URLSearchParams({
    client_id: clientID,
    redirect_uri: redirectUri,
    response_type: 'code',
    code_challenge_method: 'S256',
    code_challenge: codeChallenge,
    state: state,
    scope: 'openid profile email',
  });

  res.redirect(`${authorizationEndpoint}?${queryParams}`);
});

// OAuth callback route
app.get('/oauth/callback', async (req, res) => {
  const { code, state } = req.query;

  if (!states[state]) {
    return res.status(403).send('State mismatch or expired');
  }

  const codeVerifier = codeVerifiers[state];
  delete states[state];
  delete codeVerifiers[state];

  try {
    const response = await axios.post(tokenEndpoint, new URLSearchParams({
      client_id: clientID,
      client_secret: clientSecret,
      code,
      code_verifier: codeVerifier,
      grant_type: 'authorization_code',
      redirect_uri: redirectUri,
    }), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });

    if (response.data.access_token) {
      // Set token as httpOnly, and secure cookie
      res.cookie('token', response.data.access_token, {
        httpOnly: true, 
        secure: true, 
        maxAge: 3600000, // Token expiry time
        signed: true
      });

      res.send('Login Successful');
    } else {
      res.status(500).send('Error acquiring tokens');
    }
  } catch (error) {
    res.status(500).send('Authentication failed');
  }
});

