from abc import ABC, abstractmethod
from graphviz import Digraph
import copy

class Specification(ABC):
    @abstractmethod
    def is_satisfied_by(self, candidate):
        pass

    def and_specification(self, other):
        return AndSpecification(self, other)

    def or_specification(self, other):
        return OrSpecification(self, other)

    def not_specification(self):
        return NotSpecification(self)

class AndSpecification(Specification):
    def __init__(self, spec1, spec2):
        self.spec1 = copy.deepcopy(spec1)
        self.spec2 = copy.deepcopy(spec2)

    def is_satisfied_by(self, candidate):
        return self.spec1.is_satisfied_by(candidate) and self.spec2.is_satisfied_by(candidate)

class OrSpecification(Specification):
    def __init__(self, spec1, spec2):
        self.spec1 = copy.deepcopy(spec1)
        self.spec2 = copy.deepcopy(spec2)

    def is_satisfied_by(self, candidate):
        return self.spec1.is_satisfied_by(candidate) or self.spec2.is_satisfied_by(candidate)

class NotSpecification(Specification):
    def __init__(self, spec):
        self.spec = copy.deepcopy(spec)

    def is_satisfied_by(self, candidate):
        return not self.spec.is_satisfied_by(candidate)

class RuleEngine:
    def __init__(self, rule):
        self.root_rule = copy.deepcopy(rule)

    def evaluate(self, candidate):
        return self.root_rule.is_satisfied_by(candidate)

    def get_decision_tree(self):
        dot = Digraph()
        self._generate_graph(dot, self.root_rule, "Root")
        return dot

    def _generate_graph(self, dot, spec, parent_name):
        if isinstance(spec, AndSpecification):
            node_label = "AND"
        elif isinstance(spec, OrSpecification):
            node_label = "OR"
        elif isinstance(spec, NotSpecification):
            node_label = "NOT"
        else:
            node_label = spec.__class__.__name__

        dot.node(node_label)
        dot.edge(parent_name, node_label)

        if isinstance(spec, (AndSpecification, OrSpecification)):
            self._generate_graph(dot, spec.spec1, node_label)
            self._generate_graph(dot, spec.spec2, node_label)
        elif isinstance(spec, NotSpecification):
            self._generate_graph(dot, spec.spec, node_label)

# Example usage:

class DiscountSpecification(Specification):
    def __init__(self, discount_threshold):
        self.discount_threshold = discount_threshold

    def is_satisfied_by(self, order):
        return order.total_price >= self.discount_threshold

class CustomerTypeSpecification(Specification):
    def __init__(self, customer_type):
        self.customer_type = customer_type

    def is_satisfied_by(self, customer):
        return customer.type == self.customer_type

# Combining rules through fluent DSL
combined_spec = DiscountSpecification(100).and_specification(CustomerTypeSpecification("VIP"))

# Creating a rules engine
engine = RuleEngine(combined_spec)

# Visualizing decision tree
decision_tree = engine.get_decision_tree()
decision_tree.render('decision_tree')
