package main

import (
	"bufio"
	"compress/gzip"
	"fmt"
	"os"
	"sync"
	"time"

	"github.com/valyala/fasthttp"
)

type LogEntry struct {
	IP       string
	Date     string
	Method   string
	Resource string
	Protocol string
	Status   int
	Size     int
}

const workerCount int = 8

var (
	logEntryPool = sync.Pool{
		New: func() interface{} {
			return &LogEntry{}
		},
	}
)

func parseLine(line string, entry *LogEntry) {
	fmt.Sscanf(line, "%s [%s] \"%s %s %s\" %d %d",
		&entry.IP, &entry.Date, &entry.Method, &entry.Resource, &entry.Protocol, &entry.Status, &entry.Size)
}

func processFile(filename string, wg *sync.WaitGroup) {
	defer wg.Done()

	file, err := os.Open(filename)
	if err != nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer file.Close()

	gzReader, err := gzip.NewReader(file)
	if err != nil {
		fmt.Println("Error creating gzip reader:", err)
		return
	}
	defer gzReader.Close()

	scanner := bufio.NewScanner(gzReader)
	for scanner.Scan() {
		line := scanner.Text()
		entry := logEntryPool.Get().(*LogEntry)
		parseLine(line, entry)
		// Process log entry here...
		logEntryPool.Put(entry)
	}

	if err := scanner.Err(); err != nil {
		fmt.Println("Error reading file:", err)
		return
	}
}

func main() {
	start := time.Now()

	var wg sync.WaitGroup
	for i := 0; i < workerCount; i++ {
		filename := fmt.Sprintf("file%d.log.gz", i) // Assume file names are in this format.
		wg.Add(1)
		go processFile(filename, &wg)
	}
	wg.Wait()

	duration := time.Since(start)
	fmt.Println("Processing Time:", duration)
}
