const express = require('express');
const jwt = require('jsonwebtoken');
const bodyParser = require('body-parser');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

const SECRET_KEY = 'mysecretkey';
const REFRESH_SECRET_KEY = 'myrefreshsecretkey';
let refreshTokens = [];
let revokedTokens = [];

const generateAccessToken = (user) => {
  return jwt.sign(user, SECRET_KEY, { expiresIn: '15m' });
};

const generateRefreshToken = (user) => {
  const refreshToken = jwt.sign(user, REFRESH_SECRET_KEY);
  refreshTokens.push(refreshToken);
  return refreshToken;
};

app.post('/login', (req, res) => {
  const user = { username: req.body.username };
  const accessToken = generateAccessToken(user);
  const refreshToken = generateRefreshToken(user);
  res.json({ accessToken, refreshToken });
});

app.post('/token', (req, res) => {
  const refreshToken = req.body.token;
  if (!refreshToken || !refreshTokens.includes(refreshToken)) {
    return res.sendStatus(403);
  }

  jwt.verify(refreshToken, REFRESH_SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    const accessToken = generateAccessToken({ username: user.username });
    res.json({ accessToken });
  });
});

const verifyToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];

  if (!token) return res.sendStatus(401);
  if (revokedTokens.includes(token)) return res.sendStatus(403);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

const csrfProtection = (req, res, next) => {
  const token = req.headers['x-csrf-token'];

  if (!token || token !== req.cookies['XSRF-TOKEN']) {
    return res.status(403).json({ message: "CSRF token mismatch" });
  }
  next();
};

const preventReplayAttacks = (req, res, next) => {
  const nonce = req.headers['replay-nonce'];
  const hash = crypto.createHmac('sha256', SECRET_KEY).update(nonce).digest('hex');

  if (revokedTokens.includes(hash)) {
    return res.status(403).json({ message: "Replay attack detected" });
  }

  revokedTokens.push(hash);
  next();
};

app.post('/logout', verifyToken, (req, res) => {
  revokedTokens.push(req.headers['authorization'].split(' ')[1]);
  res.status(200).json({ message: "Logged out successfully" });
});

app.get('/protected', verifyToken, csrfProtection, preventReplayAttacks, (req, res) => {
  res.json({ message: `Welcome ${req.user.username}` });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
