        consumer.subscribe(topics);
    }

    @Override
    public ConsumerRecords<String, String> poll(Duration duration) {
        return consumer.poll(duration);
    }

    @Override
    public void commitSync() {
        consumer.commitSync();
    }

    @Override
    public void close() {
        consumer.close();
    }
}

