use actix_web::{web, App, HttpServer, Responder, HttpResponse, Error};
use actix_multipart::Multipart;
use futures::{StreamExt, TryStreamExt};
use serde::{Serialize, Deserialize};
use std::io::Write;
use std::sync::{Arc, Mutex};
use rusqlite::{params, Connection};
use std::path::PathBuf;
use uuid::Uuid;

#[derive(Serialize, Deserialize)]
struct FileUpload {
    id: String,
    file_name: String,
    file_path: String,
    total_chunks: u64,
    chunks_received: u64,
}

#[derive(Clone)]
struct AppState {
    db_conn: Arc<Mutex<Connection>>,
}

async fn handle_upload(mut payload: Multipart, data: web::Data<AppState>) -> Result<HttpResponse, Error> {
    while let Ok(Some(mut field)) = payload.try_next().await {
        let content_disposition = field.content_disposition().unwrap();
        let file_name = content_disposition.get_filename().unwrap();
        let file_id = Uuid::new_v4().to_string();
        let file_path = format!("./uploads/{}.part", &file_id);

        let mut f = web::block(move || std::fs::File::create(file_path))
            .await
            .unwrap();

        let mut chunks = 0;

        while let Some(chunk) = field.next().await {
            let data = chunk.unwrap();
            f = web::block(move || f.write_all(&data).map(|_| f))
                .await?
                .unwrap();
            chunks += 1;
        }

        let mut db = data.db_conn.lock().unwrap();
        db.execute(
            "INSERT INTO uploads (id, file_name, file_path, total_chunks, chunks_received) VALUES (?1, ?2, ?3, ?4, ?5)",
            params![
                file_id,
                file_name,
                file_path,
                chunks,
                chunks
            ],
        ).unwrap();
    }

    Ok(HttpResponse::Ok().into())
}

async fn setup_db() -> Connection {
    let conn = Connection::open("uploads.db").unwrap();
    conn.execute(
        "CREATE TABLE IF NOT EXISTS uploads (
            id TEXT PRIMARY KEY,
            file_name TEXT NOT NULL,
            file_path TEXT NOT NULL,
            total_chunks INTEGER NOT NULL,
            chunks_received INTEGER NOT NULL
            )",
        [],
    ).unwrap();
    conn
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let db_conn = Arc::new(Mutex::new(setup_db().await));

    HttpServer::new(move || {
        App::new()
            .data(AppState {
                db_conn: db_conn.clone(),
            })
            .route("/upload", web::post().to(handle_upload))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}
