import React, { useState, useCallback } from 'react';

interface JSONSchema {
  type: string;
  properties?: {
    [key: string]: JSONSchema;
  };
  items?: JSONSchema;
  description?: string;
}

const defaultSchema: JSONSchema = {
  type: "object",
  properties: {}
};

const SchemaEditor: React.FC = () => {
  const [schema, setSchema] = useState<JSONSchema>(defaultSchema);
  const [history, setHistory] = useState<JSONSchema[]>([]);
  const [future, setFuture] = useState<JSONSchema[]>([]);

  const undo = useCallback(() => {
    setFuture([schema, ...future]);
    const previous = history.pop();
    if (previous) {
      setSchema(previous);
      setHistory(history);
    }
  }, [schema, history, future]);

  const redo = useCallback(() => {
    const next = future.shift();
    if (next) {
      setHistory([...history, schema]);
      setSchema(next);
      setFuture(future);
    }
  }, [schema, history, future]);

  const updateSchema = useCallback((updatedSchema: JSONSchema) => {
    setHistory([...history, schema]);
    setSchema(updatedSchema);
    setFuture([]);
  }, [schema, history]);

  const handleChange = (key: string, value: JSONSchema, path: string) => {
    const schemaPath = path.split('.');
    let currentSchema = schema;

    schemaPath.forEach((p, index) => {
      if (index === schemaPath.length - 1) {
        if (currentSchema.properties) {
          currentSchema.properties[p] = value;
        }
      } else {
        if (currentSchema.properties && currentSchema.properties[p]) {
          currentSchema = currentSchema.properties[p];
        }
      }
    });

    updateSchema({ ...schema });
  };

  const handleAddField = (path: string) => {
    const newField: JSONSchema = { type: "string" };
    handleChange("", newField, path);
  };

  const renderSchemaFields = (schema: JSONSchema, path: string = '') => {
    if (schema.properties) {
      return Object.keys(schema.properties).map((key) => (
        <div key={key}>
          <div>{key}: {schema.properties![key].type} <button onClick={() => handleAddField(`${path}.properties.${key}`)}>Add Field</button></div>
          <div>{schema.properties![key].description && <span>{schema.properties![key].description}</span>}</div>
          <div>{renderSchemaFields(schema.properties![key], `${path}.${key}`)}</div>
        </div>
      ));
    }
    return null;
  };

  return (
    <div>
      <button onClick={undo} disabled={history.length === 0}>Undo</button>
      <button onClick={redo} disabled={future.length === 0}>Redo</button>
      <div>
        {renderSchemaFields(schema)}
      </div>
    </div>
  );
};

export default SchemaEditor;
