import java.util.regex.*;
import java.util.*;
import java.util.logging.*;

public class PiiMasker {
    private static final Logger LOGGER = Logger.getLogger(PiiMasker.class.getName());

    private Set<String> commonNames;
    private Map<Pattern, String> piiPatterns;

    public PiiMasker() {
        commonNames = loadCommonNames();
        piiPatterns = createPiiPatterns();
    }

    private Set<String> loadCommonNames() {
        // Load a list of common names from a secure source
        // This is a simplified example
        return new HashSet<>(Arrays.asList("John", "Jane", "Doe"));
    }

    private Map<Pattern, String> createPiiPatterns() {
        Map<Pattern, String> patterns = new HashMap<>();
        // Phone numbers pattern
        patterns.put(Pattern.compile("\\b(\\d{3}[-.]?\\d{3}[-.]?\\d{4})\\b"), "###-###-####");
        // Email addresses pattern
        patterns.put(Pattern.compile("\\b[a-zA-Z0-9.\\-_]+@[a-zA-Z0-9\\-_]+\\.[a-zA-Z]{2,}\\b"), "masked_email");
        return patterns;
    }

    public String maskPii(String text) {
        String maskedText = text;

        for (Map.Entry<Pattern, String> entry : piiPatterns.entrySet()) {
            Matcher matcher = entry.getKey().matcher(maskedText);
            int count = 0;
            while (matcher.find()) {
                count++;
                maskedText = matcher.replaceAll(entry.getValue());
            }
            if (count > 0) {
                LOGGER.log(Level.INFO, "PII detection confidence: {0}% for pattern {1}", new Object[]{calculateConfidence(count, text.length()), entry.getKey()});
            }
        }

        maskedText = maskBasedOnNGram(maskedText);

        return maskedText;
    }

    private String maskBasedOnNGram(String text) {
        String[] words = text.split("\\s+");
        StringBuilder maskedText = new StringBuilder();

        for (String word : words) {
            if (commonNames.contains(word)) {
                LOGGER.log(Level.INFO, "Potential PII name detected based on n-gram: {0}", word);
                maskedText.append("### ");
            } else {
                maskedText.append(word).append(" ");
            }
        }

        return maskedText.toString().trim();
    }

    private int calculateConfidence(int matches, int textLength) {
        // Simple demonstration of a confidence score based on the number of matches and text length
        double score = ((double) matches / textLength) * 100;
        return (int) Math.round(score);
    }

    public static void main(String[] args) {
        PiiMasker piiMasker = new PiiMasker();
        String exampleText = "Contact John Doe at johndoe@example.com or 123-456-7890.";
        String maskedText = piiMasker.maskPii(exampleText);
        System.out.println("Original Text: " + exampleText);
        System.out.println("Masked Text: " + maskedText);
    }
}
