// Define the trait for any knapsack solving strategy
pub trait KnapsackSolver {
    fn solve(&self, weights: &[usize], values: &[usize], capacity: usize) -> usize;
}

// Dynamic Programming implementation of the knapsack solver
pub struct DynamicProgrammingSolver;

impl KnapsackSolver for DynamicProgrammingSolver {
    fn solve(&self, weights: &[usize], values: &[usize], capacity: usize) -> usize {
        let n = weights.len();
        let mut dp = vec![vec![0; capacity + 1]; n + 1];

        for i in 1..=n {
            for j in 0..=capacity {
                if weights[i - 1] <= j {
                    dp[i][j] = dp[i - 1][j].max(values[i - 1] + dp[i - 1][j - weights[i - 1]]);
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }

        dp[n][capacity]
    }
}

// Branch-and-Bound implementation of the knapsack solver
pub struct BranchAndBoundSolver;

impl KnapsackSolver for BranchAndBoundSolver {
    fn solve(&self, weights: &[usize], values: &[usize], capacity: usize) -> usize {
        // Helper function to calculate the upper bound
        fn bound(i: usize, acc_weight: usize, acc_value: usize, weights: &[usize], values: &[usize], capacity: usize) -> usize {
            let mut weight = acc_weight;
            let mut value = acc_value;
            let mut j = i;

            while j < weights.len() && weight + weights[j] <= capacity {
                weight += weights[j];
                value += values[j];
                j += 1;
            }

            if j < weights.len() {
                value += (capacity - weight) * values[j] / weights[j];
            }

            value
        }

        // Recursive function to explore the tree
        fn recursive_solve(i: usize, current_weight: usize, current_value: usize, weights: &[usize], values: &[usize], capacity: usize, max_value: &mut usize) {
            if i == weights.len() || current_weight == capacity {
                *max_value = max_value.max(current_value);
                return;
            }

            // Calculate bound
            if bound(i, current_weight, current_value, weights, values, capacity) <= *max_value {
                return;
            }

            // Include the current item
            if current_weight + weights[i] <= capacity {
                recursive_solve(i + 1, current_weight + weights[i], current_value + values[i], weights, values, capacity, max_value);
            }

            // Exclude the current item
            recursive_solve(i + 1, current_weight, current_value, weights, values, capacity, max_value);
        }

        let mut max_value = 0;
        recursive_solve(0, 0, 0, weights, values, capacity, &mut max_value);
        max_value
    }
}

// Greedy implementation of the knapsack solver
pub struct GreedySolver;

impl KnapsackSolver for GreedySolver {
    fn solve(&self, weights: &[usize], values: &[usize], capacity: usize) -> usize {
        let mut items: Vec<(usize, usize)> = weights.iter().copied().zip(values.iter().copied()).collect();
        items.sort_by(|a, b| (b.1 as f64 / b.0 as f64).partial_cmp(&(a.1 as f64 / a.0 as f64)).unwrap());

        let mut total_value = 0;
        let mut remaining_capacity = capacity;

        for (weight, value) in items {
            if remaining_capacity == 0 {
                break;
            }
            if weight <= remaining_capacity {
                remaining_capacity -= weight;
                total_value += value;
            }
        }

        total_value
    }
}

