            solver.solve(&weights, &values, capacity) >= 0
        }

        fn prop_branch_and_bound_correct(weights: Vec<usize>, values: Vec<usize>, capacity: usize) -> bool {
            let solver = BranchAndBoundSolver;
            solver.solve(&weights, &values, capacity) >= 0
        }

        fn prop_greedy_correct(weights: Vec<usize>, values: Vec<usize>, capacity: usize) -> bool {
            let solver = GreedySolver;
            solver.solve(&weights, &values, capacity) >= 0
        }
