import akka.actor.{Actor, ActorRef, ActorSystem, Props}
import akka.routing.{FromConfig, RoundRobinPool}
import akka.pattern.ask
import akka.util.Timeout

import scala.concurrent.duration._
import scala.concurrent.Future
import scala.io.Source
import scala.collection.mutable

case class ProcessLine(line: String)
case class CountWord(word: String)
case class WordCount(word: String, count: Int)
case object Flush
case object Done

class WordCounter extends Actor {
  val counts = mutable.HashMap[String, Int]().withDefaultValue(0)

  def receive: Receive = {
    case CountWord(word) =>
      counts(word) += 1

    case Flush =>
      counts.foreach { case (word, count) =>
        sender() ! WordCount(word, count)
      }
      counts.clear()

    case Done =>
      sender() ! Done
  }
}

class Aggregator extends Actor {
  val finalCounts = mutable.HashMap[String, Int]().withDefaultValue(0)

  def receive: Receive = {
    case WordCount(word, count) =>
      finalCounts(word) += count

    case Flush =>
      sender() ! finalCounts.toMap
      context.system.terminate()
  }
}

class LineProcessor(router: ActorRef) extends Actor {
  def receive: Receive = {
    case ProcessLine(line) =>
      line.split("\\s+").foreach { word =>
        router ! CountWord(word)
      }
  }
}

object MapReduceWordCount {
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("WordCountSystem")
    val aggregator = system.actorOf(Props[Aggregator], "aggregator")
    val workers = system.actorOf(RoundRobinPool(50).props(Props[WordCounter]), "workers")
    val router = system.actorOf(FromConfig.props(Props(classOf[WordCounter], workers)), "router")
    val processor = system.actorOf(Props(classOf[LineProcessor], router), "processor")

    implicit val timeout: Timeout = Timeout(50.seconds)
    val lines = Source.fromFile("input.txt").getLines()

    lines.foreach(line => processor ! ProcessLine(line))

    Future.sequence(List.fill(50)(workers ? Flush)).map(_ => aggregator ! Flush).onComplete {
      case _ =>
        (aggregator ? Flush).mapTo[Map[String, Int]].foreach { result =>
          println("Final word counts:")
          result.toList.sortBy(-_._2).foreach { case (word, count) =>
            println(s"$word: $count")
          }
          workers ! Done
          system.terminate()
        }
    }
  }
}
