        const height = svg.attr("height");
        let data = Array.from({length: 50}, () => Math.floor(Math.random() * 400) + 10);
        let state = null;
        let timeout = null;

        const update = (annotations) => {
            svg.selectAll("rect").data(data)
                .join("rect")
                .attr("x", (d, i) => i * (width / data.length))
                .attr("y", d => height - d)
                .attr("width", width / data.length - 2)
                .attr("height", d => d)
                .attr("fill", (d, i) => annotations.includes(i) ? "red" : "steelblue");

            svg.selectAll("text").data(annotations)
                .join("text")
                .attr("x", (d, i) => annotations[i] * (width / data.length) + 5)
                .attr("y", 20)
                .text(d => `Index ${d}`)
                .attr("font-size", "10px");
        };

        const sleep = (ms) => {
          return new Promise(resolve => setTimeout(resolve, ms));
        }

        const swap = async (i, j) => {
            let temp = data[i];
            data[i] = data[j];
            data[j] = temp;
            update([i, j]);
            await sleep(300 - d3.select("#speedControl").node().value);
        };

        const partition = async (low, high) => {
            let pivot = data[high];
            let i = low - 1;
            for (let j = low; j <= high - 1; j++) {
                if (data[j] < pivot) {
                    i++;
                    await swap(i, j);
                }
            }
            await swap(i + 1, high);
            return i + 1;
        };

        const quickSort = async (low, high) => {
            if (low < high) {
                let pi = await partition(low, high);
                await quickSort(low, pi - 1);
                await quickSort(pi + 1, high);
            }
        };

        const merge = async (left, middle, right) => {
            let n1 = middle - left + 1;
            let n2 = right - middle;
            let L = new Array(n1);
            let R = new Array(n2);
            for (let i = 0; i < n1; i++)
                L[i] = data[left + i];
            for (let j = 0; j < n2; j++)
                R[j] = data[middle + 1 + j];
            let i = 0;
            let j = 0;
            let k = left;
            while (i < n1 && j < n2) {
                if (L[i] <= R[j]) {
                    data[k] = L[i];
                    i++;
                } else {
                    data[k] = R[j];
                    j++;
                }
                update([k]);
                await sleep(300 - d3.select("#speedControl").node().value);
                k++;
            }
            while (i < n1) {
                data[k] = L[i];
                i++;
                k++;
            }
            while (j < n2) {
                data[k] = R[j];
                j++;
                k++;
            }
        };

        const mergeSort = async (left, right) =>{
            if(left >= right){
                return;//returns recursively
            }
            let middle = left + Math.floor((right - left) / 2);
            await mergeSort(left, middle);
            await mergeSort(middle + 1, right);
            await merge(left, middle, right);
        }

        update([]);

        const pauseResume = () => {
            if (timeout) {
                clearTimeout(timeout);
                timeout = null;
            } else {
                quickSort(0, data.length - 1);
            }
        };

        const step = () => {
            if (!timeout) {
                quickSort(0, data.length - 1);
            }
        };

