class DataSyncService {
  constructor(networkAdapter, storageAdapter) {
    this.networkAdapter = networkAdapter;
    this.storageAdapter = storageAdapter;
  }

  async sync() {
    try {
      const localData = await this.storageAdapter.getItem('data');
      const syncStatus = await this.networkAdapter.syncData(localData);
      await this.storageAdapter.setItem('syncStatus', syncStatus);
      return syncStatus;
    } catch (error) {
      await this.storageAdapter.setItem('syncStatus', 'Sync failed');
      throw error;
    }
  }
}

