use async_std::net::TcpStream;
use async_std::task;
use serde::{Deserialize, Serialize};
use std::collections::HashSet;
use std::sync::{Arc, Mutex};
use tide::{Request, StatusCode};

const SERVER_ADDR: &str = "127.0.0.1:8080";
const TELEMETRY_ENDPOINT: &str = "0.0.0.0:9090";

// Model representing a telemetry message with timestamp and data
#[derive(Debug, Serialize, Deserialize)]
struct TelemetryData {
    timestamp: u64,
    data: String,
}

// Shared state for the telemetry server
struct TelemetryState {
    received_messages: Arc<Mutex<HashSet<u64>>>,
    write_ahead_log: Arc<Mutex<Vec<TelemetryData>>>,
}

impl TelemetryState {
    fn new() -> Self {
        TelemetryState {
            received_messages: Arc::new(Mutex::new(HashSet::new())),
            write_ahead_log: Arc::new(Mutex::new(Vec::new())),
        }
    }
}

async fn handle_telemetry_data(mut stream: TcpStream, state: Arc<TelemetryState>) {
    let mut buffer = Vec::new();
    while let Ok(size) = stream.read(&mut buffer).await {
        if size == 0 {
            break;
        }

        let data: TelemetryData = serde_json::from_slice(&buffer[..size]).unwrap();
        let mut received_messages = state.received_messages.lock().unwrap();
        if !received_messages.contains(&data.timestamp) {
            received_messages.insert(data.timestamp);
            let mut write_ahead_log = state.write_ahead_log.lock().unwrap();
            write_ahead_log.push(data.clone());

            // Simulate processing telemetry data here
            println!("Received: {:?}", data);
            buffer.clear();
        }
    }
}

async fn telemetry_server(state: Arc<TelemetryState>) {
    loop {
        match TcpStream::connect(TELEMETRY_ENDPOINT).await {
            Ok(stream) => handle_telemetry_data(stream, state.clone()).await,
            Err(e) => {
                eprintln!("Failed to connect: {}", e);
                task::sleep(std::time::Duration::from_secs(5)).await;
            },
        };
    }
}

async fn health_check(_: Request<()>) -> tide::Result {
    Ok("Service is up and running".into())
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let state = Arc::new(TelemetryState::new());
    task::spawn(telemetry_server(state.clone()));

    let mut app = tide::new();
    app.at("/health").get(health_check);
    app.listen(SERVER_ADDR).await?;
    Ok(())
}
