```go
package main

import (
	"log"
	"runtime"
	"sync"

	"github.com/fogleman/gg"
	"github.com/nareix/joy4/av/avutil"
	"github.com/nareix/joy4/av/transcode"
	"github.com/nareix/joy4/cgo/ffmpeg"
	"github.com/nareix/joy4/format"
)

const (
	maxWorkers = 4
)

type transcoderTask struct {
	sourcePath string
	targetPath string
	bitrate    int
	resolution int
}

func main() {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()

	// Register all formats and codecs
	ffmpeg.Init()

	taskChannel := make(chan *transcoderTask, 100)
	waitGroup := &sync.WaitGroup{}

	// Initialize worker pool
	for i := 0; i < maxWorkers; i++ {
		go worker(taskChannel, waitGroup)
	}

	// Example usage: Adjust this as needed
	waitGroup.Add(1)
	taskChannel <- &transcoderTask{
		sourcePath: "input.mp4",
		targetPath: "output_720p.mp4",
		bitrate:    1500000, // 1.5 Mbps
		resolution: 720,
	}

	// Remember to close the channel and wait
	close(taskChannel)
	waitGroup.Wait()
}

func worker(taskChannel <-chan *transcoderTask, waitGroup *sync.WaitGroup) {
	defer waitGroup.Done()

	for task := range taskChannel {

		err := transcodeTask(task)
		if err != nil {
			log.Printf("Error in transcoding: %s", err.Error())
		}
	}
}

func transcodeTask(task *transcoderTask) error {
	f, err := avutil.Open(task.sourcePath)
	if err != nil {
		return err
	}
	defer f.Close()

	octx, err := avutil.Create(task.targetPath)
	if err != nil {
		return err
	}
	defer octx.Close()

	streams, err := f.Streams()
	if err != nil {
		return err
	}

	var vstream transcode.VideoStream
	for _, stream := range streams {
		if stream.Type().IsVideo() {
			vcodec := stream.(transcode.CodecData)
			vstream, err = transcode.NewVideoStream(octx, vcodec)
			if err != nil {
				return err
			}

			vstream.SetBitrate(task.bitrate)
			width, height := calcResolution(stream.(transcode.VideoCodecData).Width(), stream.(transcode.VideoCodecData).Height(), task.resolution)
			vstream.SetWidth(width)
			vstream.SetHeight(height)
			break
		}
	}

	var astream transcode.AudioStream
	for _, stream := range streams {
		if stream.Type().IsAudio() {
			acodec := stream.(transcode.CodecData)
			astream, _ = transcode.NewAudioStream(octx, acodec)
		}
	}

	err = vstream.SetupDecoder(ffmpeg.CUDA_HARDWARE)
	if err != nil {
		return err
	}

	outputCtx := &transcode.OutputCtx{
		Ctx: octx,
		VideoStream: vstream,
		AudioStream: astream,
	}

	frame := avutil.NewFrame()
	for {
		_, err := f.ReadPacket()
		if err != nil {
			break
		}

		frame, err = vstream.Decode()
		if err != nil {
			continue
		}

		codedFrame, err := vstream.Encode(frame, ffmpeg.CUDA_HARDWARE)
		if err != nil {
			continue
		}

		if err = outputCtx.WritePacket(codedFrame); err != nil {
			continue
		}
	}

	err = vstream.Flush()
	if err != nil {
		return err
	}

	return nil
}

// calcResolution calculates the new width and height preserving the aspect ratio.
func calcResolution(inputWidth, inputHeight, targetHeight int) (int, int) {
	aspectRatio := float64(inputWidth) / float64(inputHeight)
	newHeight := targetHeight
	newWidth := int(aspectRatio * float64(newHeight))
	return newWidth, newHeight
}
